import{c as a,Q as o,j as l,m as t}from"./chunks/framework.D9IbVcwA.js";const h=JSON.parse('{"title":"物理内存管理 (PMM)","description":"","frontmatter":{},"headers":[],"relativePath":"document/kernel/mm/pmm.md","filePath":"document/kernel/mm/pmm.md","lastUpdated":1777209094000}'),c={name:"document/kernel/mm/pmm.md"};function i(p,e,m,r,d,n){return o(),l("div",null,[...e[0]||(e[0]=[t('<h1 id="物理内存管理-pmm" tabindex="-1">物理内存管理 (PMM) <a class="header-anchor" href="#物理内存管理-pmm" aria-label="Permalink to &quot;物理内存管理 (PMM)&quot;">​</a></h1><blockquote><p>里程碑: <code>015_mm_pmm</code></p></blockquote><h2 id="功能概述" tabindex="-1">功能概述 <a class="header-anchor" href="#功能概述" aria-label="Permalink to &quot;功能概述&quot;">​</a></h2><p>大内核的 Bitmap 物理内存分配器。解析 E820 内存图，管理 4KB 物理页面，支持单页和连续多页分配/释放。</p><h2 id="初始化" tabindex="-1">初始化 <a class="header-anchor" href="#初始化" aria-label="Permalink to &quot;初始化&quot;">​</a></h2><ol><li><code>parse_memory_map(BootInfo&amp;, regions[], max)</code> — 提取 type=1 可用区域，过滤低 1MB，对齐到 4KB</li><li>Bitmap 放于 <code>__kernel_end</code> 对齐后</li><li>先全标记已用，再将可用区域清零，最后标记内核 + bitmap 自身为已用</li></ol><h2 id="api-kernel-mm-pmm-hpp-cpp" tabindex="-1">API (<code>kernel/mm/pmm.hpp/cpp</code>) <a class="header-anchor" href="#api-kernel-mm-pmm-hpp-cpp" aria-label="Permalink to &quot;API (`kernel/mm/pmm.hpp/cpp`)&quot;">​</a></h2><ul><li><code>PMM::init(BootInfo&amp;)</code> — 初始化</li><li><code>alloc_page() → uint64_t</code> — 分配一页，返回物理地址 (0=OOM)</li><li><code>free_page(uint64_t phys)</code> — 释放一页</li><li><code>alloc_pages(count)</code> — 分配连续多页</li><li><code>free_pages(phys, count)</code> — 释放连续多页</li><li><code>free_page_count()</code> / <code>total_page_count()</code> — 统计信息</li></ul><h2 id="性能优化" tabindex="-1">性能优化 <a class="header-anchor" href="#性能优化" aria-label="Permalink to &quot;性能优化&quot;">​</a></h2><ul><li><code>alloc_page</code> 用 <code>__builtin_ctzll</code> 加速 bit 扫描 (64 位一组)</li></ul><h2 id="线程安全" tabindex="-1">线程安全 <a class="header-anchor" href="#线程安全" aria-label="Permalink to &quot;线程安全&quot;">​</a></h2><ul><li>Spinlock 保护: <code>alloc_page/alloc_pages/free_page/free_pages</code> 持锁 (TIER 0)</li></ul><h2 id="源码位置" tabindex="-1">源码位置 <a class="header-anchor" href="#源码位置" aria-label="Permalink to &quot;源码位置&quot;">​</a></h2><ul><li><code>kernel/mm/pmm.hpp/cpp</code></li></ul>',14)])])}const s=a(c,[["render",i]]);export{h as __pageData,s as default};
